// Parse Web3Forms email body into standard lead format
const emailBody = $input.first().json.text || $input.first().json.snippet || '';
const subject = $input.first().json.subject || '';

// Web3Forms sends structured text. Extract fields.
function extractField(text, fieldName) {
  const regex = new RegExp(fieldName + '[:\\s]*([^\\n]+)', 'i');
  const match = text.match(regex);
  return match ? match[1].trim() : '';
}

const name = extractField(emailBody, 'Name') || extractField(emailBody, 'name');
const email = extractField(emailBody, 'Email') || extractField(emailBody, 'email');
const company = extractField(emailBody, 'Company') || extractField(emailBody, 'company') || '';
const message = extractField(emailBody, 'Message') || extractField(emailBody, 'message') || emailBody;

return [{
  json: {
    name: name || 'Unknown (from form)',
    email: email || '',
    company: company,
    source: 'form',
    message: message,
    raw_subject: subject,
    received_at: new Date().toISOString()
  }
}];

// Normalize webhook payload into standard lead format
const input = $input.first().json;
const body = input.body || input;

return [{
  json: {
    name: body.name || '',
    email: body.email || '',
    company: body.company || '',
    source: body.source || 'manual',
    message: body.message || body.inquiry || '',
    received_at: new Date().toISOString()
  }
}];

// Parse Claude's response into usable fields
const response = $input.first().json;
const content = response.content[0].text;

let parsed;
try {
  // Handle cases where Claude wraps in markdown code blocks
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    score: 'COLD',
    confidence: 1,
    reasoning: 'Failed to parse Claude response: ' + content.substring(0, 200),
    recommended_service: 'Unknown',
    estimated_value_eur: 'Unknown',
    market: 'Other',
    urgency: 'Low',
    reply_draft: ''
  };
}

// Carry forward the original lead data from the previous node chain
const leadData = $('Merge Lead Sources').first().json;

return [{
  json: {
    // Original lead fields
    name: leadData.name,
    email: leadData.email,
    company: leadData.company,
    source: leadData.source,
    message: leadData.message,
    received_at: leadData.received_at,
    // Claude analysis
    score: parsed.score,
    confidence: parsed.confidence,
    reasoning: parsed.reasoning,
    recommended_service: parsed.recommended_service,
    estimated_value_eur: parsed.estimated_value_eur,
    market: parsed.market,
    urgency: parsed.urgency,
    reply_draft: parsed.reply_draft,
    // Meta
    scored_at: new Date().toISOString()
  }
}];

